import{_ as t,o as a,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse(`{"title":"7. Individual Flexibility Arrangements","description":"","frontmatter":{"title":"7. Individual Flexibility Arrangements","eba":"Children's Services Award 2010","topics":["leave","annual-leave","hours","overtime","penalty-rates","wages","flexible-work"]},"headers":[],"relativePath":"ebas/childrens-services/application-operation/7-individual-flexibility-arrangements.md","filePath":"ebas/childrens-services/application-operation/7-individual-flexibility-arrangements.md"}`),r={name:"ebas/childrens-services/application-operation/7-individual-flexibility-arrangements.md"};function o(l,e,p,s,d,m){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_7-individual-flexibility-arrangements" tabindex="-1">7. Individual Flexibility Arrangements <a class="header-anchor" href="#_7-individual-flexibility-arrangements" aria-label="Permalink to &quot;7. Individual Flexibility Arrangements&quot;">​</a></h1><ol><li><p>Despite anything else in this award, an employer and an individual employee may agree to vary the application of the terms of this award relating to any of the following in order to meet the genuine needs of both the employee and the employer:</p><p>a. arrangements for when work is performed; or</p><p>b. overtime rates; or</p><p>c. penalty rates; or</p><p>d. allowances; or</p><p>e. annual leave loading.</p></li><li><p>An agreement must be one that is genuinely made by the employer and the individual employee without coercion or duress.</p></li><li><p>An agreement may only be made after the individual employee has commenced employment with the employer.</p></li><li><p>An employer who wishes to initiate the making of an agreement must:</p><p>a. give the employee a written proposal; and</p><p>b. if the employer is aware that the employee has, or reasonably should be aware that the employee may have, limited understanding of written English, take reasonable steps (including providing a translation in an appropriate language) to ensure that the employee understands the proposal.</p></li><li><p>An agreement must result in the employee being better off overall at the time the agreement is made than if the agreement had not been made.</p></li><li><p>An agreement must do all of the following:</p><p>a. state the names of the employer and the employee; and</p><p>b. identify the award term, or award terms, the application of which is to be varied; and</p><p>c. set out how the application of the award term, or each award term, is varied; and</p><p>d. set out how the agreement results in the employee being better off overall at the time the agreement is made than if the agreement had not been made; and</p><p>e. state the date the agreement is to start.</p></li><li><p>An agreement must be:</p><p>a. in writing; and</p><p>b. signed by the employer and the employee and, if the employee is under 18 years of age, by the employee&#39;s parent or guardian.</p></li><li><p>Except as provided in clause 7.7(b), an agreement must not require the approval or consent of a person other than the employer and the employee.</p></li><li><p>The employer must keep the agreement as a time and wages record and give a copy to the employee.</p></li><li><p>The employer and the employee must genuinely agree, without duress or coercion to any variation of an award provided for by an agreement.</p></li><li><p>An agreement may be terminated:</p><p>a. at any time, by written agreement between the employer and the employee; or</p><p>b. by the employer or employee giving 13 weeks&#39; written notice to the other party (reduced to 4 weeks if the agreement was entered into before the first full pay period starting on or after 4 December 2013).</p></li></ol><p>Note: If an employer and employee agree to an arrangement that purports to be an individual flexibility arrangement under this award term and the arrangement does not meet a requirement set out in s.144 then the employee or the employer may terminate the arrangement by giving written notice of not more than 28 days (see s.145 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>).</p><ol><li><p>An agreement terminated as mentioned in clause 7.11(b) ceases to have effect at the end of the period of notice required under that clause.</p></li><li><p>The right to make an agreement under clause 7 is additional to, and does not affect, any other term of this award that provides for an agreement between an employer and an individual employee.</p></li></ol><p>Plain language terms: IFA, individual flex.</p>',5)])])}const g=t(r,[["render",o]]);export{y as __pageData,g as default};
